import React, { useState, useEffect } from 'react';
import axios from 'axios';
// Grafikleri çizebilmek için gerekli parçaları ekliyoruz
import { 
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer, PieChart, Pie, Cell, Legend 
} from 'recharts';
import './App.css';

const API_BASE_URL = 'http://127.0.0.1:5000/api';
const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8'];

function App() {
  // 1. Durum (State) Tanımları
  const [data, setData] = useState(null);
  const [chartData, setChartData] = useState({ trend: [], categories: [] });
  const [loading, setLoading] = useState(true);

  // 2. Veri Çekme Fonksiyonu
  useEffect(() => {
    const fetchEverything = async () => {
      try {
        // İki API isteğini aynı anda başlatıyoruz
        const [kpiRes, chartRes] = await Promise.all([
          axios.get(`${API_BASE_URL}/kpi/summary`),
          axios.get(`${API_BASE_URL}/charts/data`)
        ]);
        setData(kpiRes.data);
        setChartData(chartRes.data);
        setLoading(false);
      } catch (err) {
        console.error("Veri çekme hatası:", err);
        setLoading(false);
      }
    };
    fetchEverything();
  }, []);

  if (loading) return <div style={{textAlign: 'center', padding: '50px'}}><h2>📊 Veriler Hazırlanıyor...</h2></div>;

  return (
    <div className="App">
      <div className="dashboard-container">
        {/* Başlık */}
        <header className="header" style={{ marginBottom: '20px' }}>
          <h1>📊 InsightFlow KDS: E-Ticaret Performans Panosu</h1>
          <p style={{color: '#27ae60', fontWeight: 'bold'}}>Canlı Veri Bağlantısı: Aktif ✅</p>
        </header>

        {/* KPI Kartları */}
        <div className="kpi-cards" style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '30px' }}>
          <div style={cardStyle}>
            <span style={labelStyle}>Toplam Ciro</span>
            <div style={valueStyle}>₺{data?.total_revenue.toLocaleString()}</div>
          </div>
          <div style={cardStyle}>
            <span style={labelStyle}>Dönüşüm Oranı</span>
            <div style={valueStyle}>%{data?.conversion_rate}</div>
          </div>
          <div style={cardStyle}>
            <span style={labelStyle}>Müşteri Sayısı</span>
            <div style={valueStyle}>{data?.unique_customers}</div>
          </div>
          <div style={cardStyle}>
            <span style={labelStyle}>Ort. Sipariş Değeri</span>
            <div style={valueStyle}>₺{data?.aov.toFixed(2)}</div>
          </div>
        </div>

        {/* GRAFİK ALANI */}
        <div className="charts-area" style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '20px' }}>

          {/* Sol Taraf: Çizgi Grafik */}
          <div style={chartStyle}>
            <h3 style={{marginBottom: '15px'}}>Aylık Satış Trendi</h3>
            <ResponsiveContainer width="100%" height={350}>
              <LineChart data={chartData.trend}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip />
                <Line type="monotone" dataKey="value" stroke="#8884d8" strokeWidth={3} dot={{r: 5}} />
              </LineChart>
            </ResponsiveContainer>
          </div>

          {/* Sağ Taraf: Pasta Grafik */}
          <div style={chartStyle}>
            <h3 style={{marginBottom: '15px'}}>Kategori Dağılımı</h3>
            <ResponsiveContainer width="100%" height={350}>
              <PieChart>
                <Pie 
                  data={chartData.categories} 
                  dataKey="value" 
                  nameKey="name" 
                  cx="50%" cy="50%" 
                  outerRadius={80} 
                  label
                >
                  {chartData.categories.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </div>

        </div>

        {/* Alt Detay */}
        <div className="details-area" style={{ marginTop: '30px', padding: '20px', borderTop: '1px solid #eee' }}>
          <p>Toplam İşlenen Sipariş: <strong>{data?.total_orders}</strong></p>
        </div>
      </div>
    </div>
  );
}

// Stiller
const cardStyle = {
  flex: 1, margin: '0 10px', padding: '20px', backgroundColor: '#fff',
  borderRadius: '10px', boxShadow: '0 4px 10px rgba(0,0,0,0.1)', textAlign: 'center'
};

const labelStyle = { fontSize: '0.8em', color: '#888', textTransform: 'uppercase', display: 'block' };
const valueStyle = { fontSize: '1.5em', fontWeight: 'bold', color: '#2c3e50', marginTop: '5px' };

const chartStyle = {
  backgroundColor: '#fff', padding: '20px', borderRadius: '10px',
  boxShadow: '0 4px 10px rgba(0,0,0,0.1)'
};

export default App;
